import java.io.*;
import java.util.*;

public class Main {
    private static final String ORDER = "!#$%&*?@^";
    private static final int[] RANK = new int[128];
    static {
        for (int i = 0; i < ORDER.length(); i++) {
            RANK[ORDER.charAt(i)] = i;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            StringTokenizer st = new StringTokenizer(br.readLine());
            Character[] nuts = new Character[N];
            for (int i = 0; i < N; i++) {
                nuts[i] = st.nextToken().charAt(0);
            }
            st = new StringTokenizer(br.readLine());
            Character[] bolts = new Character[N];
            for (int i = 0; i < N; i++) {
                bolts[i] = st.nextToken().charAt(0);
            }
            Arrays.sort(nuts, Comparator.comparingInt(c -> RANK[c]));
            Arrays.sort(bolts, Comparator.comparingInt(c -> RANK[c]));
            for (int i = 0; i < N; i++) {
                out.append(nuts[i]);
                if (i + 1 < N) out.append(' ');
            }
            out.append('\n');
            for (int i = 0; i < N; i++) {
                out.append(bolts[i]);
                if (i + 1 < N) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

